//verifica id da sessao.
verificaidsessao.Call(&DevRandon, &IsAcessoConcedido, &IsAtualizaTudo, &wwpContext)


if &IsAcessoConcedido = true //Acesso concedido
	&LogGUID = GUID.NewGuid()
//	&LogItemConteudo = &AuxsdtCapaPedido

	&EmpCod = &wwpContext.EmpCod
	&FilCod = &parFilCod
	&PedCod = &parPedCod

	&QtdErros = 0
	RetornaConfSistema_PedidoVendas.Call(&wwpContext.EmpCod, &wwpContext.FilCod, &SdtConfig_wwpVendas_3)

	CarregaSdtPerfil_api.Call(&wwpContext.EmpCod, &wwpContext.PesCod, &AutGrpCod, &AutGrpNom)
	RetornaAutorizacaoApi.Call('TELEVENDATROCARVENDEDOR', &wwpContext, &AutGrpCod, &TrocarVendedorAutNiv)
	if &TrocarVendedorAutNiv > 1
		RetornaAutorizacaoApi.Call('VENDEDORDIGITAPEDIDOS', &wwpContext, &AutGrpCod, &TrocarVendedorAutNiv)
	Endif
	&PossuiModuloAGRO_INSUMOS = RetornaEmpresaModulo.UDP(&wwpContext.EmpCod, ModuloSistema.AGRO_INSUMOS)

	RetornaAutorizacaoApi.CALL('VENDAPRAZOFORACOLUNA', &wwpContext, &AutGrpCod, &PermiteAlterarPrazo)	

	If &wwpContext.PesIsVen = true
		&AuxPedVenCod = &wwpContext.PesCod
	EndIF

	&IsAutorizado = true
	If &PedCod <> 0
		&IsAutorizado = false
		RetornaIsPodeAlterar_api.Call(&wwpContext, &wwpContext.EmpCod, &FilCod, &PedCod, &IsAutorizado)
	EndIf

	if &IsAutorizado = false
		&QtdErros += 1
		&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
		&sdtRetornoWbsEtc.Obs += 'Não autorizado a editar o pedido! '
	else //autorizado a editar

		if &PedCod <> 0
			&TrnMode = TrnMode.Update
			CarregaSdtPedidoVenda.Call(&EmpCod, &FilCod, &PedCod, &sdtGravaPedido)
		Else
			&TrnMode = TrnMode.Insert

			&PedStsDigBlk = false
			//			if &DeOndeVem <> 'PEDIDOTELEVENDAS'
			&sdtGravaPedido.PedStsGer = Pedido_Gerado.Vendas
			//			Else	
			//				&sdtGravaPedido.PedStsGer = Pedido_Gerado.Vendas
			//				If &SdtConfig_wwpVendas_3.TCon058_DigitandoPedido = 'S'
			//					&PedStsDigBlk = true
			//				EndIF
			//Endif

			&sdtGravaPedido.PedStsDigBlk = &PedStsDigBlk		
		Endif

