		&oldUpdTabPrmCod = &sdtGravaPedido.TabPrmCod
		&OldUpdTabColCod = &sdtGravaPedido.TabColCod
		&OldPedVenCod = &sdtGravaPedido.PedVenCod
		&OldUpdPedPraCod = &sdtGravaPedido.PedPraCod
		&OldPedTraSaiCod = &sdtGravaPedido.PedTraSaiCod
		&oldPedTipSaiFrt = &sdtGravaPedido.PedTipSaiFrt
		&OldPedTraRedCod = &sdtGravaPedido.PedTraRedCod

		&sdtGravaPedido.PedCliCod = &sdtCapaPedidoNovo.PedCliCod
		&sdtGravaPedido.LctCod = &sdtCapaPedidoNovo.LctCod

		timestampToDate.Call(&sdtCapaPedidoNovo.PedDtaEmsTmpSec, &PedDtaEms)
		&sdtGravaPedido.PedDtaEms = &PedDtaEms


		if &sdtCapaPedidoNovo.PedDtaPrvTmpSec > 0
			timestampToDate.Call(&sdtCapaPedidoNovo.PedDtaPrvTmpSec, &sdtGravaPedido.PedDtaPrv)
		Else
			&sdtGravaPedido.PedDtaPrv = &PedDtaPRv //vazio
		Endif

		&sdtGravaPedido.TabCod = &sdtCapaPedidoNovo.TabCod
		&sdtGravaPedido.TabPrmCod = &sdtCapaPedidoNovo.TabPrmCod

		&sdtGravaPedido.TabColCod = &sdtCapaPedidoNovo.TabColCod

		&sdtGravaPedido.PedNum = &sdtCapaPedidoNovo.PedNum

		&sdtGravaPedido.PedVenCod = &sdtCapaPedidoNovo.PedVenCod

