		&sdtGravaPedido.PedPerFrt = &sdtCapaPedidoNovo.valPedPerFrt
		&sdtGravaPedido.PedFrtFix = &sdtCapaPedidoNovo.valPedFrtFix

		&sdtGravaPedido.PedPerSpm1 = &sdtCapaPedidoNovo.valPedPerSpm1
