		&sdtGravaPedido.PedPerPrm1 = &sdtCapaPedidoNovo.valPedPerPrm1
		&sdtGravaPedido.PedPerPrm2 = &sdtCapaPedidoNovo.valPedPerPrm2
		//		
		//		&sdtGravaPedido.PedPrpCod = &PedPrpCod		
		//		
		//		&sdtGravaPedido.PedCtaBanCod = &PedCtaBanCod
		//		&sdtGravaPedido.PedEmbDes = &PedEmbDes		
		//		
		//		if &PraTipParc = '1'
		//			&sdtVencimentosInformados.Clear()
		//			
		//			if not &CreDtaVct1.IsEmpty()
		//				&sdtVencimentosItem = new()
		//				&sdtVencimentosItem.CreDtaVct = &CreDtaVct1
		//				&sdtVencimentosInformados.Add(&sdtVencimentosItem)
		//			Endif
		//			
		//			if not &CreDtaVct2.IsEmpty()
		//				&sdtVencimentosItem = new()
		//				&sdtVencimentosItem.CreDtaVct = &CreDtaVct2
		//				&sdtVencimentosInformados.Add(&sdtVencimentosItem)
		//			Endif
		//			
		//			if not &CreDtaVct3.IsEmpty()	
		//				&sdtVencimentosItem = new()
		//				&sdtVencimentosItem.CreDtaVct = &CreDtaVct3
		//				&sdtVencimentosInformados.Add(&sdtVencimentosItem)
		//			Endif
		//			
		//			if not &CreDtaVct4.IsEmpty()	
		//				&sdtVencimentosItem = new()
		//				&sdtVencimentosItem.CreDtaVct = &CreDtaVct4
		//				&sdtVencimentosInformados.Add(&sdtVencimentosItem)
		//			Endif
		//			
		//			if not &CreDtaVct5.IsEmpty()	
		//				&sdtVencimentosItem = new()
		//				&sdtVencimentosItem.CreDtaVct = &CreDtaVct5
		//				&sdtVencimentosInformados.Add(&sdtVencimentosItem)
		//			Endif			
		//			
		//			if not &CreDtaVct6.IsEmpty()	
		//				&sdtVencimentosItem = new()
		//				&sdtVencimentosItem.CreDtaVct = &CreDtaVct6
		//				&sdtVencimentosInformados.Add(&sdtVencimentosItem)
		//			Endif
		//			
		//			if &sdtVencimentosInformados.Count = 0
		//				&sdtVencimentosItem = new()
		//				&sdtVencimentosItem.CreDtaVct = &PedDtaEms+1
		//				&sdtVencimentosInformados.Add(&sdtVencimentosItem)
		//			Endif		
		//		Endif
		//		
		//		&sdtGravaPedido.PedPraParDesc = &PedPraParDesc
	Endif
	do 'loadTipoLancamento'
	if &IsErroTipoLancamento = false
		do 'LoadCliente'
		if &IsErroCliente = false
			do 'LoadVendedor'
			if &IsErroVendedor = false	
				do 'loadTabela'
				do 'loadTabelaPromocao'
				do 'loadColuna'
				if &Iserrotabela = false and &IserroColuna = false and &IsErroTabelaPromocao = false
