&sdtRetornoWbsEtc.Detalhes = &sdtCapaPedidoNovo.ToJson()

sub 'GravarPedido'
	//PROC, GRAVA PEDIDO
	GravaPedidoVenda.Call(&TrnMode, &EmpCod, &FilCod, &PedCod, &sdtGravaPedido, &wwpContext.PesCod, &wwpContext.UserName)

	&sdtRetornoWbsEtc.c1 = trim(str(&PedCod))
	&sdtRetornoWbsEtc.sts = 'J200'
	&sdtRetornoWbsEtc.Obs += 'pedido atualizado! '
	//		GravaPedidoVendaVencimentos.Call(&EmpCod, &FilCod, &PedCod, &sdtVencimentosInformados, &Context.UserName)
	//		GravaPedidoVenda_PedDtaVct.Call(&EmpCod, &FilCod, &PedCod)	

EndSub


Sub 'loadTabela'
	&Iserrotabela = false

	If (&TrnMode = TrnMode.insert or (&TrnMode = TrnMode.update and &oldUpdTabCod <> &sdtGravaPedido.TabCod))
		TestaTabelasPedidoVenda.Call(&EmpCod, &FilCod, &sdtGravaPedido.TabCod, StatusTabela.NormalAtiva, &PedCliCidUfeCod, &PedDtaEms, &PedCliCidAreCod, &TabelaMensagem)

		If &TabelaMensagem <> '' 
			&Iserrotabela = true
			&QtdErros += 1
			&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
			&sdtRetornoWbsEtc.Obs += &TabelaMensagem + ' '
		EndIf
	EndIf
EndSub

Sub 'LoadtabelaPromocao'

	&IsErroTabelaPromocao = false

	If (&TrnMode = TrnMode.insert or (&TrnMode = TrnMode.update and &oldUpdTabPrmCod <> &sdtGravaPedido.TabPrmCod))
		TestaTabelasPedidoVenda.Call(&EmpCod, &FilCod, &sdtGravaPedido.TabPrmCod, StatusTabela.Promocao, &PedCliCidUfeCod, &PedDtaEms, &PedCliCidAreCod, &TabelaPromocaoMensagem)

		If &TabelaPromocaoMensagem <> '' 
			&IsErroTabelaPromocao = true
			&QtdErros += 1
			&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
			&sdtRetornoWbsEtc.Obs += &TabelaPromocaoMensagem + ' '
		EndIf
	EndIf

EndSub

Sub 'LoadColuna'

//	If &PermiteAlterarColuna = 1
//		&sdtGravaPedido.TabColCod.Enabled = True
//	Else
//		&sdtGravaPedido.TabColCod.Enabled = false
//	EndIf

	&IserroColuna = false

	If (&sdtGravaPedido.TabColCod < 1 or &sdtGravaPedido.TabColCod > 9) 
		&IserroColuna = true

		&QtdErros += 1
		&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
		&sdtRetornoWbsEtc.Obs += 'Coluna de Preço Inválida! '
	Else
		For Each Order EmpCod, TabCod, TabColCod
			Where EmpCod = &EmpCod
			Where TabCod = &sdtGravaPedido.TabCod
			Where TabColCod = &sdtGravaPedido.TabColCod

			//tbVencimento.Visible = TabIsAntAcr

			&TabColPrzPad = TabColPrzPad
			Exit
		When none
			&IserroColuna = true
			&QtdErros += 1
			&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
			&sdtRetornoWbsEtc.Obs += 'Coluna de Preço Inválida! '
		EndFor
	Endif

EndSub


Sub 'loadPrazo'

	&IsErroPrazo = false	
	RetornaPrazo.Call(&EmpCod, &sdtGravaPedido.PedPraCod, &pedPraColMax, &PedPraColMin, &PedPraMedBlo, &PraTipParc, &PraQtdMax,&PraIsVis)

	//	tbParcelas.Visible = (&PraTipParc = '0')
	//	tbParcelasVct.Visible = (&PraTipParc = '0') //EM DIAS
	//	tbDatasVencimentos0.Visible = (&PraTipParc = '1') //EM DATAS
	//	tbPrazoDescritivo.Visible  = (&PraTipParc = '3') //DESCRITIVO

	//	if &PraTipParc = '1'
	//		tbVencimento2.Visible = &PraQtdMax > 1
	//		tbVencimento3.Visible = &PraQtdMax > 2
	//		tbVencimento4.Visible = &PraQtdMax > 3
	//		tbVencimento5.Visible = &PraQtdMax > 4
	//		tbVencimento6.Visible = &PraQtdMax > 5
	//	Endif

	Do Case
		CASE (&PermiteAlterarPrazo = 0) and ((&pedPraColMax < &sdtGravaPedido.TabColCod and not &pedPraColMax.IsEmpty()) or (&PedPraColMin > &sdtGravaPedido.TabColCod and not &PedPraColMin.IsEmpty())) and (&OldUpdTabColCod <> &sdtGravaPedido.TabColCod or &OldUpdPedPraCod <> &sdtGravaPedido.PedPraCod)
			&IsErroPrazo = true
			&QtdErros += 1
			&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
			&sdtRetornoWbsEtc.Obs += 'Prazo incompatível com coluna da tabela de preço!, Não Autorizado a vender Fora do prazo! '
		Case &PesVenAprz = 'N' and &PraIsVis = false
			&IsErroPrazo = true
			&QtdErros += 1
			&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
			&sdtRetornoWbsEtc.Obs += 'Não é permitido venda a prazo para este cliente, Selecione um prazo considerado a vista! '
	EndCase

EndSub

Sub 'loadParcelaPrazo'

	FormataParcelaMax.Call(&sdtGravaPedido.PedPraParNom, &PraQtdMax, &sdtGravaPedido.PedPraParNom)

	&IsErroParcelaPrazo = false	//PRAZO MEDIO PEDIDO
	if &PedPraMedBlo <> 0 and &PraTipParc = '0'
		&AuxPedPraMedBlo = RetornaPrazoMedio.Udp(&sdtGravaPedido.PedPraParNom) 

		if &PedPraMedBlo <> 0 and &AuxPedPraMedBlo > &PedPraMedBlo
			&IsErroParcelaPrazo = true

			&QtdErros += 1
			&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
			&sdtRetornoWbsEtc.Obs += 'Prazo médio maior que o Autorizado! Médio Cálculado:' + trim(str(&AuxPedPraMedBlo)) + ' Máximo Autorizado:' + trim(str(&PedPraMedBlo)) + ' '
		Endif
	Endif

EndSub

Sub 'LoadVendedor'

	For Each Order EmpCod, PesCod
		Where EmpCod = &EmpCod
		Where PesCod = &sdtGravaPedido.PedVenCod

		&IsErroVendedor = false		

		&PesDtaDem = RetornaDataRecrutamento.udp(EmpCod, PesCod,'D')

		Do CAse
			Case (&PedCliCidAreCod <> PesVenAreCod) and (&PedCliCidAreCod <> 0) and &sdtConfig_wwpVendas_3.TCon021_BloquearVendaAreaDiferente = 'S'
				&IsErroVendedor = true
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Vendedor não autorizado a vender na área ' +trim(str(&PedCliCidAreCod))+ '! '

			Case ((PesVenIntExt = Status_InternoExterno.INTERNO and PesCod <> &PedCliIntVenCod and &PedCliIntVenCod <> 1) or (PesVenIntExt = Status_InternoExterno.EXTERNO and PesCod <> &PedCliExtVenCod and &PedCliExtVenCod <> 1)) and &sdtGravaPedido.PedCliCod <> 1 and &sdtGravaPedido.PedCliCod <> &sdtConfig_wwpVendas_3.TCon020_ClientePadraoVista and &TrocarVendedorAutNiv < 1
				&IsErroVendedor = true
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Vendedor atual é o Televendas: ' +trim(str(&PedCliIntVenCod))+ ' e o Vendedor: ' +trim(str(&PedCliExtVenCod))+ '. Com o informado não pode! '

			CAse  PesIsVen <> true and (&PedCod = 0 or &OldPedVenCod <> &sdtGravaPedido.PedVenCod or &OldPedCliCod <> &sdtGravaPedido.PedCliCod)
				&IsErroVendedor = true
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Vendedor é obrigatório. '

			CAse not &PesDtaDem.IsEmpty() and (&PedCod = 0 or &OldPedVenCod <> &sdtGravaPedido.PedVenCod or &OldPedCliCod <> &sdtGravaPedido.PedCliCod)
				&IsErroVendedor = true
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Vendedor está demitido. '

			Case PesSts = Status_AtivoInativo.INATIVO and (&PedCod = 0 or &OldPedVenCod <> &sdtGravaPedido.PedVenCod or &OldPedCliCod <> &sdtGravaPedido.PedCliCod)
				&IsErroVendedor = true
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += ' Vendedor está inativo. '

		EndCase

		Exit		
	When none
		&IsErroVendedor = true
		&QtdErros += 1
		&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
		&sdtRetornoWbsEtc.Obs += 'Vendedor é obrigatório. '
	EndFor

EndSub

Sub 'LoadCliente'

	&IsErroCliente = false
	For Each Order EmpCod, PesCod
		Where EmpCod = &EmpCod
		Where PesCod = &sdtGravaPedido.PedCliCod

		Do Case
			Case PesSts <> Status_AtivoInativo.ATIVO and (&PedCod = 0 or &OldPedCliCod <> &sdtGravaPedido.PedCliCod) //VERIFICAR REGRA				
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Cliente com Cadastro inativado! '
				&IsErroCliente = true
			Case PesIsCli <> true and PesIsFor <> true and (&PedCod = 0 or &OldPedCliCod <> &sdtGravaPedido.PedCliCod)
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Cliente é obrigatório! '				
				&IsErroCliente = true
		EndCase		

		&PedCliCidUfeCod = PesCidUfeCod		
		&PedCliCidAreCod = PesCidAreCod
		&PedCliIntVenCod = PesIntVenCod
		&PedCliExtVenCod = PesExtVenCod		
		&PedCliCidCod = PesCidCod
		&PedCliTpcCod = TpcCod		

		Exit
	When none
		&IsErroCliente = true
		&QtdErros += 1
		&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
		&sdtRetornoWbsEtc.Obs += 'Cliente inválido! '
	EndFor

