Sub 'LoadTipoLancamento'

	&IsErroTipoLancamento = false

	For Each Order EmpCod, LctCod
		Where EmpCod = &EmpCod
		Where LctCod = &sdtGravaPedido.LctCod


		Do Case
			Case LctAtuSal <> Status_EntradaSaida.Saida or (LctTip <> TipoLancamento.OrcamentoVenda and LctTip <> TipoLancamento.SaidaMercadoria)
				&IsErroTipoLancamento = true
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Tipo de Lançamento inválido, para Pedido de Venda!'

				//case ((LctTip <> TipoLancamento.OrcamentoVenda and &TrocarVendedorAutNiv < 1 and &PedCod = 0) or (&OldLctCod <> LctCod and &PedCod <> 0 and &TrocarVendedorAutNiv < 1 )) and &DeOndeVem = 'PEDIDOTELEVENDAS' and &SdtConfig_wwpVendas_3.TCon193_SomenteOrcamentoVendaTelevendas <> 'N'
				//	&QtdErros += 1
				//	&&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				//	&&sdtRetornoWbsEtc.Obs += 'Habilitado Somente para Digitar Orçamento!'
				//	&IsErroTipoLancamento = true
		EndCase

		//		&LctInfAnoSafCul = LctInfAnoSafCul
		//		&LctAtuEst = LctAtuEst

		//		&PedRomCha = LctCha
		//		&PedRomCrt = LctCrt
		If LctTabColCod <> 0 and (&sdtGravaPedido.TabColCod = 0 or &sdtGravaPedido.TabColCod.IsEmpty())
			&sdtGravaPedido.TabColCod = LctTabColCod
		EndIf

		Exit
	When None
		&IsErroTipoLancamento = true
		&QtdErros += 1
		&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
		&sdtRetornoWbsEtc.Obs += 'Tipo Lançamento é obrigatório!'
	EndFor

	//	tbAnosaf.Visible = &PossuiModuloAGRO_INSUMOS = 'S' and &LctInfAnoSafCul = Status_SimNao.Sim
	//	tbAnoSaf1.Visible = &PossuiModuloAGRO_INSUMOS = 'S' and &LctInfAnoSafCul = Status_SimNao.Sim
	//	
//	if (&PedSts = Status_Pedido.FECHADO or &PedSts = Status_Pedido.SEPARANDO) and (&LctAtuEst <> &OldLctAtuEst)
//		&mensagem = 'Mudança de Código de Lançamento não Permitida!!'
//		do 'mensagemErro'
//		&IsErroTipoLancamento = true
//	EndiF

EndSub


Sub 'loadTransportadoraRedespacho'

	&IsErroTransportadoraRedespacho= false
	For Each Order EmpCod, PesCod
		Where EmpCod = &EmpCod
		Where PesCod = &sdtGravaPedido.PedTraRedCod

		Do Case
			CAse PesIsTra.IsEmpty() and (&oldPedTraRedCod <> &sdtGravaPedido.PedTraRedCod or &OldPedCliCod <> &sdtGravaPedido.PedCliCod)
				&IsErroTransportadoraRedespacho = true
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Transportadora Redespacho Inválida!'

			Case PesSts = Status_AtivoInativo.INATIVO and (&oldPedTraRedCod <> &sdtGravaPedido.PedTraRedCod or &OldPedCliCod <> &sdtGravaPedido.PedCliCod)
				&IsErroTransportadoraRedespacho = true
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Transportadora Redespacho está com status Inativo! '
		EndCase

		Exit
	When none
		if &sdtGravaPedido.PedTipFrt <> TipoFrete.SemFrete
			&IsErroTransportadoraRedespacho = true
			&QtdErros += 1
			&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
			&sdtRetornoWbsEtc.Obs += 'Transportadora Redespacho não localizada, Inválida!'
		Endif	
	EndFor	
EndSub


Sub 'LoadTransportadoraSaida'

	&IsErroTransportadoraSaida= false
	For Each Order EmpCod, PesCod
		Where EmpCod = &EmpCod
		Where PesCod = &sdtGravaPedido.PedTraSaiCod

		do case
			CAse PesIsTra.IsEmpty() and (&OldPedTraSaiCod <> &sdtGravaPedido.PedTraSaiCod or &OldPedCliCod <> &sdtGravaPedido.PedCliCod)
				&IsErroTransportadoraSaida = true
				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'Transportadora saída Inválida!'

			Case PesSts = Status_AtivoInativo.INATIVO and (&OldPedTraSaiCod <> &sdtGravaPedido.PedTraSaiCod or &OldPedCliCod <> &sdtGravaPedido.PedCliCod)
				&IsErroTransportadoraSaida = true

				&QtdErros += 1
				&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
				&sdtRetornoWbsEtc.Obs += 'ATENÇÃO! Transportadora está com status Inativo. Verifique!'
		EndCase

		Exit
	When none
		if &sdtGravaPedido.PedTipSaiFrt <> TipoFrete.SemFrete
			&IsErroTransportadoraSaida = true
			&QtdErros += 1
			&sdtRetornoWbsEtc.Sts = 'E' + padL(trim(str(&QtdErros)), 3, '0')
			&sdtRetornoWbsEtc.Obs += 'Transportadora não localizada, Inválida!'
		Endif
	EndFor
EndSub



Sub 'Exception_handler'
	&sdtRetornowbs.Sts = 'E999'
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Exception_handler: &GXexceptionType',&GXexceptionType)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Exception_handler: &GXExceptionDetails',&GXExceptionDetails)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Exception_handler: &GXExceptionStack',&GXExceptionStack)
Endsub

Sub 'Error_handler'
	&sdtRetornowbs.Sts = 'E998'
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &Err',&Err.ToFormattedString())
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxDBErr',&gxDBErr.ToFormattedString())
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &GxDbSqlState',&GxDbSqlState)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxDBTxt',&gxDBTxt)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxOper',&gxOper)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxErrTbl',&gxErrTbl)
	GravaLogDevNew(&wwpContext.EmpCod,&LogGUID,&Pgmname,'Error_handler: &gxErrOpt',&gxErrOpt.ToFormattedString())
Endsub

